  1	import * as React from 'react';
  2	import { Label } from '@patternfly/react-core';
  3	import {
  4	  TektonHubTask,
  5	  useInclusterTektonHubURLs,
  6	  useTektonHubResources,
  7	} from '../apis/tektonHub';
  8	import {
  9	  filterBySupportedPlatforms,
 10	  useTektonHubIntegration,
 11	} from '../catalog-utils';
 12	import {
 13	  CatalogItem,
 14	  ExtensionHook,
 15	  ResourceIcon,
 16	  useAccessReview,
 17	} from '@openshift-console/dynamic-plugin-sdk';
 18	import { TaskModel } from '../../../models';
 19	import { TaskProviders } from '../../task-quicksearch/pipeline-quicksearch-utils';
 20	import { getReferenceForModel } from '../../pipelines-overview/utils';
 21	import { t } from '../../utils/common-utils';
 22	
 23	const normalizeTektonHubTasks = (
 24	  tektonHubTasks: TektonHubTask[],
 25	  apiURL: string,
 26	  uiURL: string,
 27	): CatalogItem<TektonHubTask>[] => {
 28	  const normalizedTektonHubTasks: CatalogItem<TektonHubTask>[] = tektonHubTasks
 29	    .filter(filterBySupportedPlatforms)
 30	    .reduce((acc, task) => {
 31	      if (task.kind !== TaskModel.kind) {
 32	        return acc;
 33	      }
 34	      const { id, name } = task;
 35	      const { description } = task.latestVersion;
 36	      const provider = TaskProviders.tektonHub;
 37	      const tags = task.tags?.map((t) => t.name) ?? [];
 38	      const categories = task.categories?.map((ct) => ct.name) ?? [];
 39	      const [secondaryLabelName] = categories;
 40	      const versions = [];
 41	      const normalizedTektonTask: CatalogItem<TektonHubTask> = {
 42	        uid: id.toString(),
 43	        type: TaskProviders.community,
 44	        name,
 45	        description,
 46	        provider,
 47	        tags,
 48	        secondaryLabel: secondaryLabelName && (
 49	          <Label color="blue">{secondaryLabelName}</Label>
 50	        ),
 51	        icon: {
 52	          node: <ResourceIcon kind={getReferenceForModel(TaskModel)} />,
 53	        },
 54	        attributes: { installed: '', versions, categories, apiURL, uiURL },
 55	        cta: {
 56	          label: t('Add'),
 57	        },
 58	        data: task,
 59	      };
 60	      acc.push(normalizedTektonTask);
 61	
 62	      return acc;
 63	    }, []);
 64	
 65	  return normalizedTektonHubTasks;
 66	};
 67	
 68	const useTektonHubTasksProvider: ExtensionHook<CatalogItem[]> = ({
 69	  namespace,
 70	}): [CatalogItem[], boolean, string] => {
 71	  const [normalizedTektonHubTasks, setNormalizedTektonHubTasks] =
 72	    React.useState<CatalogItem<TektonHubTask>[]>([]);
 73	
 74	  const canCreateTask = useAccessReview({
 75	    group: TaskModel.apiGroup,
 76	    resource: TaskModel.plural,
 77	    namespace,
 78	    verb: 'create',
 79	  });
 80	
 81	  const canUpdateTask = useAccessReview({
 82	    group: TaskModel.apiGroup,
 83	    resource: TaskModel.plural,
 84	    namespace,
 85	    verb: 'update',
 86	  });
 87	
 88	  const integrationEnabled = useTektonHubIntegration();
 89	  const { apiURL, uiURL, loaded: baseURLLoaded } = useInclusterTektonHubURLs();
 90	
 91	  const [tektonHubTasks, tasksLoaded, tasksError] = useTektonHubResources(
 92	    apiURL,
 93	    canCreateTask && canUpdateTask && integrationEnabled && baseURLLoaded,
 94	  );
 95	
 96	  React.useMemo(
 97	    () =>
 98	      setNormalizedTektonHubTasks(
 99	        normalizeTektonHubTasks(tektonHubTasks, apiURL, uiURL),
100	      ),
101	    [apiURL, tektonHubTasks, uiURL],
102	  );
103	  return [normalizedTektonHubTasks, tasksLoaded, tasksError];
104	};
105	
106	export default useTektonHubTasksProvider;

